<?php
require __DIR__.'/../includes/bootstrap.php';require_auth();$id=(int)($_GET['id']??0);$s=db()->prepare('SELECT * FROM companies WHERE id=?');$s->execute([$id]);$c=$s->fetch();if(!$c){http_response_code(404);exit('Company not found.');}if(!can_manage_company($c)){http_response_code(403);exit('Company owner or administrator access required.');}$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$name=trim($_POST['name']??'');if($name==='')throw new RuntimeException('Company name is required.');$website=trim($_POST['website']??'');if($website!==''&&!filter_var($website,FILTER_VALIDATE_URL))throw new RuntimeException('Enter a complete website URL.');$email=trim($_POST['public_email']??'');if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL))throw new RuntimeException('Enter a valid public email.');$logo=save_uploaded_image('logo','companies/logos',$id);$banner=save_uploaded_image('banner','companies/banners',$id);$sql='UPDATE companies SET name=?,short_description=?,description=?,website=?,public_email=?,phone=?,location=?,category=?,founded_year=?'.($logo?',logo_path=?':'').($banner?',banner_path=?':'').' WHERE id=?';$args=[$name,trim($_POST['short_description']??''),trim($_POST['description']??''),$website,$email,trim($_POST['phone']??''),trim($_POST['location']??''),trim($_POST['category']??''),((int)($_POST['founded_year']??0))?:null];if($logo)$args[]=$logo;if($banner)$args[]=$banner;$args[]=$id;db()->prepare($sql)->execute($args);flash('success','Company updated.');redirect('dashboard.php?id='.$id);}catch(Throwable $e){$error=$e->getMessage();}}
app_header('Edit '.$c['name']);?><section class="dashboard-hero"><p class="eyebrow">COMPANY MANAGEMENT</p><h1>Edit Company</h1></section><?php if($error):?><div class="alert error"><?=e($error)?></div><?php endif?><form class="profile-form" method="post" enctype="multipart/form-data"><?=csrf_field()?><section class="app-card form-grid"><label>Company name<input name="name" required value="<?=e($c['name'])?>"></label><label>Category<input name="category" value="<?=e($c['category'])?>"></label><label class="full">Short description<input name="short_description" maxlength="280" value="<?=e($c['short_description'])?>"></label><label class="full">Description<textarea name="description"><?=e($c['description'])?></textarea></label><label>Website<input type="url" name="website" value="<?=e($c['website'])?>"></label><label>Public email<input type="email" name="public_email" value="<?=e($c['public_email'])?>"></label><label>Phone<input name="phone" value="<?=e($c['phone'])?>"></label><label>Location<input name="location" value="<?=e($c['location'])?>"></label><label>Founded year<input type="number" name="founded_year" min="1500" max="<?=date('Y')?>" value="<?=e((string)$c['founded_year'])?>"></label><label>Replace logo<input type="file" name="logo" accept="image/jpeg,image/png,image/webp,image/gif"></label><label>Replace banner<input type="file" name="banner" accept="image/jpeg,image/png,image/webp,image/gif"></label></section><div class="form-actions"><a class="button ghost" href="dashboard.php?id=<?=$id?>">Cancel</a><button class="button primary">Save Company</button></div></form><?php app_footer();
